    30→  }>({});
    31→
    32→  // Shape of the actual session_ended payload from backend
    33→  interface SessionEndedPayload {
    34→    summary?: string;
    35→    stats?: { items_shown: number; likes: number; dislikes: number };
    36→    liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
    37→    user_name?: string;
    38→  }
    39→
    40→  // Check for returning user on mount
    41→  useEffect(() => {
    42→    async function checkReturning() {
    43→      const savedId = localStorage.getItem(STORAGE_KEY);
    44→      if (savedId) {
    45→        try {
    46→          const existingUser = await getUser(savedId);
    47→          setUser(existingUser);
