    86→      // Fire-and-forget: update name, upload selfie, start scrape
    87→      updateProfile(profile.id, displayName).catch(() => {});
    88→      if (selfieBase64) {
    89→        uploadSelfie(profile.id, selfieBase64).catch(() => {});
    90→      }
    91→      startScrape(profile.id).catch(() => {});
    92→
    93→      setState("questionnaire");
    94→    },
    95→    []
    96→  );
    97→
    98→  const handleQuestionnaireSubmit = useCallback(
    99→    async (data: OnboardingData) => {
   100→      if (!user) return;
   101→      await submitOnboarding(user.id, data);
   102→      setState("queue");
   103→    },
   104→    [user]
   105→  );
   106→
   107→  const handleBecameActive = useCallback(() => {
   108→    setState("idle");
   109→  }, []);
   110→
   111→  const handleLeaveQueue = useCallback(() => {
   112→    localStorage.removeItem(STORAGE_KEY);
   113→    setUser(null);
