   232→
   233→/* ---------- Questionnaire View ---------- */
   234→
   235→const STYLE_OPTIONS = [
   236→  "Casual", "Streetwear", "Minimalist", "Preppy",
   237→  "Athleisure", "Vintage", "Smart Casual", "Bohemian",
   238→];
   239→
   240→const OCCASION_OPTIONS = [
   241→  "Everyday", "Work", "Date Night", "Workout", "Weekend", "Travel",
   242→];
   243→
   244→function QuestionnaireView({
   245→  onSubmit,
   246→}: {
   247→  onSubmit: (data: OnboardingData) => void;
   248→}) {
   249→  const [brands, setBrands] = useState("");
   250→  const [styles, setStyles] = useState<string[]>([]);
   251→  const [occasions, setOccasions] = useState<string[]>([]);
   252→  const [gender, setGender] = useState("unspecified");
   253→  const [priceMin, setPriceMin] = useState(0);
   254→  const [priceMax, setPriceMax] = useState(300);
   255→
   256→  function toggle(arr: string[], val: string, setter: (v: string[]) => void) {
   257→    setter(arr.includes(val) ? arr.filter((x) => x !== val) : [...arr, val]);
   258→  }
   259→
   260→  function handleSubmit() {
   261→    onSubmit({
   262→      favorite_brands: brands.split(",").map((b) => b.trim()).filter(Boolean),
   263→      style_preferences: styles,
   264→      price_range: { min: priceMin, max: priceMax },
   265→      size_info: {},
   266→      gender,
   267→      occasions,
   268→    });
   269→  }
   270→
   271→  return (
   272→    <div className="p-4 max-w-lg mx-auto pb-6">
   273→      <h2 className="text-xl font-bold mb-0.5">Let&apos;s get to know you</h2>
   274→      <p className="text-zinc-500 text-xs mb-4">
   275→        Quick style questions to personalize your experience.
   276→      </p>
   277→
   278→      {/* Gender */}
   279→      <label className="block text-xs font-semibold mb-1">Gender</label>
   280→      <select
   281→        value={gender}
   282→        onChange={(e) => setGender(e.target.value)}
   283→        className="w-full px-3 py-2 border border-zinc-200 rounded-lg text-sm mb-3 focus:outline-none focus:ring-2 focus:ring-zinc-900"
   284→      >
   285→        <option value="mens">Men</option>
   286→        <option value="womens">Women</option>
   287→        <option value="unspecified">Prefer not to say</option>
   288→      </select>
   289→
   290→      {/* Brands */}
   291→      <label className="block text-xs font-semibold mb-1">
   292→        Favorite brands (comma-separated)
   293→      </label>
   294→      <input
   295→        value={brands}
   296→        onChange={(e) => setBrands(e.target.value)}
   297→        placeholder="Nike, Zara, Uniqlo"
   298→        className="w-full px-3 py-2 border border-zinc-200 rounded-lg text-sm mb-3 focus:outline-none focus:ring-2 focus:ring-zinc-900"
   299→      />
   300→
   301→      {/* Style */}
   302→      <label className="block text-xs font-semibold mb-1.5">Style preferences</label>
   303→      <div className="flex flex-wrap gap-1.5 mb-3">
   304→        {STYLE_OPTIONS.map((s) => (
   305→          <button
   306→            key={s}
   307→            onClick={() => toggle(styles, s, setStyles)}
   308→            className={`px-3 py-1.5 rounded-full text-xs border transition-colors ${
   309→              styles.includes(s)
   310→                ? "bg-zinc-900 text-white border-zinc-900"
   311→                : "bg-white text-zinc-700 border-zinc-200 hover:border-zinc-400"
   312→            }`}
   313→          >
   314→            {s}
   315→          </button>
   316→        ))}
   317→      </div>
   318→
   319→      {/* Occasions */}
   320→      <label className="block text-xs font-semibold mb-1.5">Occasions</label>
   321→      <div className="flex flex-wrap gap-1.5 mb-3">
   322→        {OCCASION_OPTIONS.map((o) => (
   323→          <button
   324→            key={o}
   325→            onClick={() => toggle(occasions, o, setOccasions)}
   326→            className={`px-3 py-1.5 rounded-full text-xs border transition-colors ${
   327→              occasions.includes(o)
   328→                ? "bg-zinc-900 text-white border-zinc-900"
   329→                : "bg-white text-zinc-700 border-zinc-200 hover:border-zinc-400"
