   331→          >
   332→            {o}
   333→          </button>
   334→        ))}
   335→      </div>
   336→
   337→      {/* Price range */}
   338→      <label className="block text-xs font-semibold mb-1.5">
   339→        Price range: ${priceMin} – ${priceMax}
   340→      </label>
   341→      <div className="flex gap-3 items-center mb-4">
   342→        <input
   343→          type="range"
   344→          min={0}
   345→          max={500}
   346→          step={10}
   347→          value={priceMin}
   348→          onChange={(e) => setPriceMin(Number(e.target.value))}
   349→          className="flex-1"
   350→        />
   351→        <input
   352→          type="range"
   353→          min={0}
   354→          max={500}
   355→          step={10}
   356→          value={priceMax}
   357→          onChange={(e) => setPriceMax(Number(e.target.value))}
   358→          className="flex-1"
   359→        />
   360→      </div>
   361→
   362→      <button
   363→        onClick={handleSubmit}
   364→        className="w-full bg-zinc-900 text-white rounded-xl py-3 text-sm font-semibold"
   365→      >
   366→        Join Queue
   367→      </button>
   368→    </div>
   369→  );
   370→}
   371→
   372→/* ---------- Idle View ---------- */
   373→
   374→const TIPS = [
   375→  "Try saying: \"I want something for a night out\"",
   376→  "Give a thumbs up to save items you like",
   377→  "Swipe left or right to browse outfits",
   378→  "Ask Mira about your style or upcoming events",
   379→];
   380→
   381→function IdleView() {
   382→  const [tipIndex, setTipIndex] = useState(0);
   383→  const [elapsed, setElapsed] = useState(0);
   384→
   385→  useEffect(() => {
   386→    const tipTimer = setInterval(() => {
   387→      setTipIndex((i) => (i + 1) % TIPS.length);
   388→    }, 5000);
   389→    const clockTimer = setInterval(() => {
   390→      setElapsed((s) => s + 1);
   391→    }, 1000);
   392→    return () => {
   393→      clearInterval(tipTimer);
   394→      clearInterval(clockTimer);
   395→    };
   396→  }, []);
   397→
   398→  const minutes = Math.floor(elapsed / 60);
   399→  const seconds = elapsed % 60;
   400→
   401→  return (
   402→    <div className="flex flex-col items-center justify-center min-h-screen p-4 gap-4">
   403→      <div className="w-14 h-14 rounded-full bg-green-500 flex items-center justify-center">
   404→        <span className="text-white text-2xl">✦</span>
   405→      </div>
   406→
   407→      <h2 className="text-xl font-bold text-center">
   408→        You&apos;re at the mirror!
   409→      </h2>
   410→
   411→      <div className="h-10 flex items-center">
   412→        <p className="text-zinc-500 text-center text-xs animate-pulse transition-all">
   413→          {TIPS[tipIndex]}
   414→        </p>
   415→      </div>
   416→
   417→      <div className="text-zinc-400 text-xs font-mono">
   418→        {String(minutes).padStart(2, "0")}:{String(seconds).padStart(2, "0")}
   419→      </div>
   420→    </div>
   421→  );
   422→}
   423→
   424→/* ---------- Recap View ---------- */
   425→
   426→function RecapView({
   427→  data,
   428→  onDone,
   429→}: {
   430→  data: { summary?: string; items_shown?: number; items_liked?: number };
   431→  onDone: () => void;
   432→}) {
   433→  return (
   434→    <div className="flex flex-col items-center justify-center min-h-screen p-4 gap-4">
   435→      <h2 className="text-xl font-bold">Session Complete</h2>
   436→
   437→      {data.summary && (
   438→        <p className="text-zinc-600 text-center text-sm max-w-sm">{data.summary}</p>
   439→      )}
   440→
   441→      <div className="flex gap-6">
   442→        {data.items_shown !== undefined && (
   443→          <div className="text-center">
   444→            <p className="text-2xl font-bold">{data.items_shown}</p>
   445→            <p className="text-xs text-zinc-500">Items Shown</p>
   446→          </div>
   447→        )}
   448→        {data.items_liked !== undefined && (
   449→          <div className="text-center">
   450→            <p className="text-2xl font-bold">{data.items_liked}</p>
   451→            <p className="text-xs text-zinc-500">Liked</p>
   452→          </div>
   453→        )}
   454→      </div>
   455→
   456→      {process.env.NEXT_PUBLIC_POKE_RECIPE_URL && (
   457→        <a
   458→          href={process.env.NEXT_PUBLIC_POKE_RECIPE_URL}
   459→          target="_blank"
   460→          rel="noopener noreferrer"
   461→          style={{
   462→            display: "block",
   463→            width: "100%",
   464→            maxWidth: "24rem",
   465→            padding: "12px 20px",
   466→            fontSize: 14,
   467→            fontWeight: 600,
   468→            color: "#fff",
   469→            background: "#5B4FE9",
   470→            border: "none",
   471→            borderRadius: 12,
   472→            textAlign: "center",
   473→            textDecoration: "none",
   474→            boxSizing: "border-box",
   475→          }}
   476→        >
   477→          Continue on Poke
   478→        </a>
   479→      )}
   480→
   481→      <button
   482→        onClick={onDone}
   483→        className="w-full max-w-sm bg-zinc-900 text-white rounded-xl py-3 text-sm font-semibold"
   484→      >
